mapper.select:
SELECT id, teacher_id, content, priority, completed, due_date, created_at, updated_at, is_deleted
FROM teacher_todos
WHERE id = #{id}
  AND teacher_id = #{teacherId}
  AND is_deleted = 0

mapper.update:
UPDATE teacher_todos
SET is_deleted = 1,
    updated_at = NOW()
WHERE id = #{id}
  AND teacher_id = #{teacherId}
  AND is_deleted = 0
